import { useState, useEffect, useCallback } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
  useListPatients,
  useListDoctors,
  useGetPatientContext,
  useExtractKnowledge,
  useDetectConflicts,
  useConfirmNode,
  useDismissNode,
  useMergeNode,
  useUndoNode,
  getGetCaptureSummaryQueryKey,
  getListKnowledgeNodesQueryKey,
  getGetPatientContextQueryKey,
  CaptureCandidate,
  KnowledgeNode,
} from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import {
  Mic, Upload, StopCircle, RefreshCw, CheckCircle, XCircle,
  PlayCircle, ShieldAlert, CheckSquare, AlertTriangle, Info,
  GitMerge, Undo2, Loader2, ChevronRight, Eye, Clock
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const transcriptionSchema = z.object({
  patientId: z.string().min(1, "Patient is required"),
  doctorId: z.string().min(1, "Doctor is required"),
  transcript: z.string().min(10, "Transcript must be at least 10 characters"),
});

type ConflictResult = {
  candidateId: number;
  conflictType: "NEW" | "COEXIST" | "UPDATE" | "DUPLICATE";
  similarity: number;
  existingNode: KnowledgeNode | null;
};

type UndoEntry = { nodeId: number; title: string; expiresAt: number };

function getTypeIcon(type: string) {
  switch (type) {
    case "CONSTRAINT": return <ShieldAlert className="h-3.5 w-3.5 text-red-500" />;
    case "DECISION": return <CheckSquare className="h-3.5 w-3.5 text-primary" />;
    case "ANTI_PATTERN": return <AlertTriangle className="h-3.5 w-3.5 text-orange-500" />;
    case "FACT": return <Info className="h-3.5 w-3.5 text-blue-500" />;
    default: return <Info className="h-3.5 w-3.5" />;
  }
}

function conflictBadgeVariant(ct: string) {
  if (ct === "DUPLICATE") return "destructive";
  if (ct === "UPDATE") return "default";
  if (ct === "COEXIST") return "secondary";
  return "outline";
}

function tierColor(tier: string) {
  if (tier === "HIGH") return "border-l-green-500";
  if (tier === "MEDIUM") return "border-l-yellow-500";
  return "border-l-red-500";
}

export default function Pipeline() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState<"capture" | "review">("capture");
  const [audioFile, setAudioFile] = useState<File | null>(null);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [candidates, setCandidates] = useState<CaptureCandidate[]>([]);
  const [conflicts, setConflicts] = useState<Record<number, ConflictResult>>({});
  const [detectingFor, setDetectingFor] = useState<Set<number>>(new Set());
  const [undoQueue, setUndoQueue] = useState<UndoEntry[]>([]);
  const [dismissed, setDismissed] = useState<Set<number>>(new Set());

  const { data: patients } = useListPatients();
  const { data: doctors } = useListDoctors();
  const extractMutation = useExtractKnowledge();
  const detectConflicts = useDetectConflicts();
  const confirmNode = useConfirmNode();
  const dismissNode = useDismissNode();
  const undoNode = useUndoNode();

  const form = useForm<z.infer<typeof transcriptionSchema>>({
    resolver: zodResolver(transcriptionSchema),
    defaultValues: { patientId: "", doctorId: "", transcript: "" },
  });

  const selectedPatientId = form.watch("patientId");

  const { data: patientCtx } = useGetPatientContext(
    Number(selectedPatientId),
    { query: { enabled: !!selectedPatientId && selectedPatientId !== "", queryKey: getGetPatientContextQueryKey(Number(selectedPatientId)) } }
  );

  // Auto-detect conflicts when candidates arrive
  useEffect(() => {
    if (candidates.length === 0) return;
    for (const c of candidates) {
      if (conflicts[c.id] || detectingFor.has(c.id)) continue;
      setDetectingFor(prev => new Set(prev).add(c.id));
      detectConflicts.mutateAsync({ data: { candidateId: c.id } })
        .then(result => {
          setConflicts(prev => ({ ...prev, [c.id]: result as ConflictResult }));
        })
        .catch(() => {})
        .finally(() => {
          setDetectingFor(prev => { const s = new Set(prev); s.delete(c.id); return s; });
        });
    }
  }, [candidates]);

  const handleTranscribe = async () => {
    if (!audioFile) return;
    setIsTranscribing(true);
    try {
      const fd = new FormData();
      fd.append("audio", audioFile);
      const res = await fetch("/api/transcribe", { method: "POST", body: fd });
      if (!res.ok) throw new Error();
      const data = await res.json();
      form.setValue("transcript", data.transcript);
      toast({ title: "Transcription complete" });
    } catch {
      toast({ title: "Transcription failed", variant: "destructive" });
    } finally {
      setIsTranscribing(false);
    }
  };

  const onSubmit = async (values: z.infer<typeof transcriptionSchema>) => {
    try {
      const result = await extractMutation.mutateAsync({
        data: {
          patientId: Number(values.patientId),
          doctorId: Number(values.doctorId),
          transcript: values.transcript,
        },
      });
      setCandidates(result);
      setConflicts({});
      setDismissed(new Set());
      setActiveTab("review");
      toast({ title: "Extraction complete", description: `Found ${result.length} candidates` });
    } catch {
      toast({ title: "Extraction failed", description: "Check that OPENAI_API_KEY is set", variant: "destructive" });
    }
  };

  const handleConfirm = async (candidate: CaptureCandidate, edits?: Partial<CaptureCandidate>) => {
    try {
      const node = await confirmNode.mutateAsync({
        data: {
          candidateId: candidate.id,
          editedType: edits?.type,
          editedTitle: edits?.title,
          editedContent: edits?.content,
          editedRationale: edits?.rationale,
        },
      });
      setDismissed(prev => new Set(prev).add(candidate.id));
      queryClient.invalidateQueries({ queryKey: getGetCaptureSummaryQueryKey() });
      queryClient.invalidateQueries({ queryKey: getListKnowledgeNodesQueryKey() });
      if (selectedPatientId) queryClient.invalidateQueries({ queryKey: getGetPatientContextQueryKey(Number(selectedPatientId)) });
      // HIGH tier gets 60s undo
      if (candidate.confidenceTier === "HIGH") {
        setUndoQueue(prev => [...prev, { nodeId: node.id, title: node.title, expiresAt: Date.now() + 60000 }]);
      }
      toast({ title: "Node confirmed", description: node.title });
    } catch {
      toast({ title: "Failed to confirm", variant: "destructive" });
    }
  };

  const handleDismiss = async (candidateId: number) => {
    try {
      await dismissNode.mutateAsync({ data: { candidateId } });
      setDismissed(prev => new Set(prev).add(candidateId));
      toast({ title: "Candidate dismissed" });
    } catch {
      toast({ title: "Failed to dismiss", variant: "destructive" });
    }
  };

  const handleUndo = async (entry: UndoEntry) => {
    try {
      await undoNode.mutateAsync({ data: { nodeId: entry.nodeId } });
      setUndoQueue(prev => prev.filter(u => u.nodeId !== entry.nodeId));
      queryClient.invalidateQueries({ queryKey: getGetCaptureSummaryQueryKey() });
      queryClient.invalidateQueries({ queryKey: getListKnowledgeNodesQueryKey() });
      toast({ title: "Node undone", description: entry.title });
    } catch {
      toast({ title: "Undo window expired", variant: "destructive" });
      setUndoQueue(prev => prev.filter(u => u.nodeId !== entry.nodeId));
    }
  };

  const activeCount = candidates.filter(c => !dismissed.has(c.id)).length;

  return (
    <div className="p-8 space-y-6 max-w-6xl mx-auto">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Capture Pipeline</h1>
        <p className="text-muted-foreground mt-2">Convert clinical transcripts into validated knowledge nodes.</p>
      </div>

      {/* Undo queue */}
      {undoQueue.length > 0 && (
        <div className="space-y-2">
          {undoQueue.map(entry => (
            <UndoBar key={entry.nodeId} entry={entry} onUndo={() => handleUndo(entry)} onExpire={() => setUndoQueue(prev => prev.filter(u => u.nodeId !== entry.nodeId))} />
          ))}
        </div>
      )}

      {/* Tabs */}
      <div className="flex space-x-1 border-b border-border">
        {(["capture", "review"] as const).map((tab, i) => (
          <button
            key={tab}
            data-testid={`tab-${tab}`}
            className={`pb-2 px-4 text-sm font-medium transition-colors ${activeTab === tab ? "border-b-2 border-primary text-primary" : "text-muted-foreground hover:text-foreground"} ${tab === "review" && candidates.length === 0 ? "opacity-40 cursor-not-allowed" : ""}`}
            onClick={() => tab === "review" && candidates.length === 0 ? undefined : setActiveTab(tab)}
          >
            {i + 1}. {tab === "capture" ? "Capture & Extract" : `Review Candidates (${activeCount})`}
          </button>
        ))}
      </div>

      {activeTab === "capture" && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Main capture form */}
          <div className="lg:col-span-2">
            <Card>
              <CardHeader>
                <CardTitle>Transcript Input</CardTitle>
                <CardDescription>Select patient and doctor, then record or paste a clinical transcript.</CardDescription>
              </CardHeader>
              <CardContent>
                <Form {...form}>
                  <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-5">
                    <div className="grid grid-cols-2 gap-4">
                      <FormField
                        control={form.control}
                        name="patientId"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Patient</FormLabel>
                            <Select onValueChange={field.onChange} value={field.value}>
                              <FormControl>
                                <SelectTrigger data-testid="select-patient">
                                  <SelectValue placeholder="Select patient..." />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                {patients?.map(p => (
                                  <SelectItem key={p.id} value={p.id.toString()} data-testid={`option-patient-${p.id}`}>
                                    {p.name} · {p.mrn}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="doctorId"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Doctor</FormLabel>
                            <Select onValueChange={field.onChange} value={field.value}>
                              <FormControl>
                                <SelectTrigger data-testid="select-doctor">
                                  <SelectValue placeholder="Select doctor..." />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                {doctors?.map(d => (
                                  <SelectItem key={d.id} value={d.id.toString()} data-testid={`option-doctor-${d.id}`}>
                                    {d.name} · {d.specialty}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>

                    {/* Audio controls */}
                    <div className="flex flex-wrap items-center gap-3 p-3 bg-muted/40 rounded-lg border border-dashed border-border">
                      <div className="relative">
                        <Input data-testid="input-audio-upload" type="file" accept="audio/*" onChange={e => setAudioFile(e.target.files?.[0] || null)} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full z-10" />
                        <Button type="button" variant="outline" size="sm">
                          <Upload className="mr-2 h-4 w-4" /> Upload Audio
                        </Button>
                      </div>
                      {audioFile && (
                        <>
                          <span className="text-sm text-muted-foreground truncate max-w-[160px]">{audioFile.name}</span>
                          <Button data-testid="button-transcribe" type="button" size="sm" onClick={handleTranscribe} disabled={isTranscribing}>
                            {isTranscribing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <PlayCircle className="mr-2 h-4 w-4" />}
                            {isTranscribing ? "Transcribing..." : "Transcribe"}
                          </Button>
                        </>
                      )}
                    </div>

                    <FormField
                      control={form.control}
                      name="transcript"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Transcript / Clinical Notes</FormLabel>
                          <FormControl>
                            <Textarea data-testid="input-transcript" placeholder="Paste or dictate transcript here..." className="h-52 font-mono text-sm resize-none" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <Button data-testid="button-extract" type="submit" disabled={extractMutation.isPending} className="w-full">
                      {extractMutation.isPending ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" /> Extracting knowledge nodes...</> : <>Extract Knowledge Nodes <ChevronRight className="ml-2 h-4 w-4" /></>}
                    </Button>
                  </form>
                </Form>
              </CardContent>
            </Card>
          </div>

          {/* Patient context panel */}
          <div className="space-y-4">
            <Card className="h-full">
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <Eye className="h-4 w-4 text-muted-foreground" /> Patient Context
                </CardTitle>
                <CardDescription className="text-xs">Existing knowledge nodes for the selected patient.</CardDescription>
              </CardHeader>
              <CardContent>
                {!selectedPatientId ? (
                  <p className="text-sm text-muted-foreground text-center py-8">Select a patient to see their knowledge context.</p>
                ) : !patientCtx ? (
                  <div className="flex items-center justify-center py-8"><Loader2 className="h-4 w-4 animate-spin text-muted-foreground" /></div>
                ) : patientCtx.knowledgeNodes.length === 0 ? (
                  <div className="text-center py-8">
                    <p className="text-sm font-medium">{patientCtx.patient.name}</p>
                    <p className="text-xs text-muted-foreground mt-1">No existing knowledge nodes.</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    <p className="text-sm font-semibold">{patientCtx.patient.name} <span className="font-normal text-muted-foreground">· {patientCtx.patient.mrn}</span></p>
                    <div className="space-y-2 max-h-[420px] overflow-y-auto pr-1">
                      {patientCtx.knowledgeNodes.map(node => (
                        <div key={node.id} data-testid={`context-node-${node.id}`} className="p-2.5 rounded-md border bg-muted/30 space-y-1">
                          <div className="flex items-center gap-1.5">
                            {getTypeIcon(node.type)}
                            <span className="text-xs font-medium truncate">{node.title}</span>
                          </div>
                          <p className="text-xs text-muted-foreground line-clamp-2">{node.content}</p>
                          <div className="flex gap-1 mt-1">
                            <Badge variant="outline" className="text-[9px] h-4">{node.type}</Badge>
                            <Badge variant="secondary" className="text-[9px] h-4">{(node.confidence * 100).toFixed(0)}% conf</Badge>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      )}

      {activeTab === "review" && (
        <div className="space-y-4">
          {candidates.length === 0 && (
            <div className="text-center p-12 bg-muted/30 rounded-lg border border-dashed border-border">
              <p className="text-muted-foreground">No candidates to review.</p>
            </div>
          )}
          {candidates.map(candidate => (
            dismissed.has(candidate.id) ? (
              <div key={candidate.id} className="p-3 rounded-lg border border-dashed border-border/50 bg-muted/20 flex items-center gap-3 opacity-50">
                <CheckCircle className="h-4 w-4 text-muted-foreground shrink-0" />
                <span className="text-sm text-muted-foreground line-through">{candidate.title}</span>
              </div>
            ) : (
              <CandidateCard
                key={candidate.id}
                candidate={candidate}
                conflict={conflicts[candidate.id]}
                isDetecting={detectingFor.has(candidate.id)}
                onConfirm={(edits) => handleConfirm(candidate, edits)}
                onDismiss={() => handleDismiss(candidate.id)}
              />
            )
          ))}
        </div>
      )}
    </div>
  );
}

// ─── Undo bar ───────────────────────────────────────────────────────────────

function UndoBar({ entry, onUndo, onExpire }: { entry: UndoEntry; onUndo: () => void; onExpire: () => void }) {
  const [remaining, setRemaining] = useState(Math.max(0, Math.round((entry.expiresAt - Date.now()) / 1000)));
  const undoNode = useUndoNode();

  useEffect(() => {
    const interval = setInterval(() => {
      const left = Math.max(0, Math.round((entry.expiresAt - Date.now()) / 1000));
      setRemaining(left);
      if (left === 0) { clearInterval(interval); onExpire(); }
    }, 500);
    return () => clearInterval(interval);
  }, [entry.expiresAt]);

  return (
    <div data-testid={`undo-bar-${entry.nodeId}`} className="flex items-center justify-between p-3 rounded-lg bg-green-50 border border-green-200 text-sm">
      <div className="flex items-center gap-2">
        <CheckCircle className="h-4 w-4 text-green-600" />
        <span className="font-medium text-green-800">Auto-captured: <span className="font-normal">{entry.title}</span></span>
      </div>
      <div className="flex items-center gap-3">
        <span className="text-green-600 text-xs flex items-center gap-1"><Clock className="h-3 w-3" /> {remaining}s</span>
        <Button data-testid={`button-undo-${entry.nodeId}`} variant="outline" size="sm" onClick={onUndo} disabled={undoNode.isPending} className="h-7 text-xs border-green-300 hover:bg-green-100">
          <Undo2 className="h-3 w-3 mr-1" /> Undo
        </Button>
      </div>
    </div>
  );
}

// ─── Candidate card ──────────────────────────────────────────────────────────

function CandidateCard({
  candidate, conflict, isDetecting, onConfirm, onDismiss,
}: {
  candidate: CaptureCandidate;
  conflict?: ConflictResult;
  isDetecting: boolean;
  onConfirm: (edits?: Partial<CaptureCandidate>) => void;
  onDismiss: () => void;
}) {
  const [editing, setEditing] = useState(false);
  const [editedTitle, setEditedTitle] = useState(candidate.title);
  const [editedContent, setEditedContent] = useState(candidate.content);
  const [editedType, setEditedType] = useState(candidate.type);
  const [editedRationale, setEditedRationale] = useState(candidate.rationale ?? "");
  const [isPending, setIsPending] = useState(false);
  const mergeMutation = useMergeNode();
  const queryClient = useQueryClient();
  const { toast } = useToast();

  const tier = candidate.confidenceTier;
  const requiresEdit = tier === "LOW";
  const requiresReview = tier === "MEDIUM" || requiresEdit;

  // LOW always opens in edit mode
  useEffect(() => {
    if (requiresEdit) setEditing(true);
  }, [requiresEdit]);

  const handleConfirm = async () => {
    setIsPending(true);
    try {
      if (editing) {
        await onConfirm({ type: editedType as CaptureCandidate["type"], title: editedTitle, content: editedContent, rationale: editedRationale });
      } else {
        await onConfirm();
      }
    } finally {
      setIsPending(false);
    }
  };

  const handleMerge = async (existingNodeId: number) => {
    setIsPending(true);
    try {
      await mergeMutation.mutateAsync({ data: { candidateId: candidate.id, existingNodeId } });
      queryClient.invalidateQueries({ queryKey: getGetCaptureSummaryQueryKey() });
      queryClient.invalidateQueries({ queryKey: getListKnowledgeNodesQueryKey() });
      toast({ title: "Merged into existing node" });
      onDismiss();
    } catch {
      toast({ title: "Merge failed", variant: "destructive" });
    } finally {
      setIsPending(false);
    }
  };

  return (
    <Card data-testid={`candidate-card-${candidate.id}`} className={`border-l-4 ${tierColor(tier)}`}>
      <CardHeader className="pb-3">
        <div className="flex items-start justify-between gap-4">
          <div className="flex items-center gap-2 flex-wrap">
            {getTypeIcon(candidate.type)}
            <span className="font-semibold text-base">{candidate.title}</span>
            <Badge variant="outline" className="text-xs">{candidate.type}</Badge>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <Badge variant={tier === "HIGH" ? "default" : tier === "MEDIUM" ? "secondary" : "destructive"} className="text-xs">
              {tier} · {(candidate.confidence * 100).toFixed(0)}%
            </Badge>
          </div>
        </div>
        <p className="text-xs text-muted-foreground">{candidate.department} · {candidate.suggestedLevel} level</p>
      </CardHeader>

      <CardContent className="space-y-4">
        {/* Tier guidance */}
        {tier === "HIGH" && (
          <div className="flex items-center gap-2 text-xs text-green-700 bg-green-50 border border-green-200 rounded-md px-3 py-2">
            <CheckCircle className="h-3.5 w-3.5 shrink-0" />
            High confidence — will auto-capture with a 60-second undo window.
          </div>
        )}
        {tier === "LOW" && (
          <div className="flex items-center gap-2 text-xs text-red-700 bg-red-50 border border-red-200 rounded-md px-3 py-2">
            <AlertTriangle className="h-3.5 w-3.5 shrink-0" />
            Low confidence — review and edit before confirming.
          </div>
        )}

        {/* Conflict detection */}
        <div className="p-3 bg-muted/40 rounded-md border border-border/60">
          <p className="text-xs font-semibold mb-2 text-muted-foreground uppercase tracking-wide">Conflict Detection</p>
          {isDetecting && (
            <div className="flex items-center gap-2 text-xs text-muted-foreground">
              <Loader2 className="h-3 w-3 animate-spin" /> Scanning knowledge graph...
            </div>
          )}
          {!isDetecting && conflict && (
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                <Badge variant={conflictBadgeVariant(conflict.conflictType)} className="text-xs">
                  {conflict.conflictType}
                </Badge>
                <span className="text-xs text-muted-foreground">similarity: {(conflict.similarity * 100).toFixed(1)}%</span>
              </div>
              {conflict.existingNode && (
                <div className="p-2 bg-background rounded border text-xs space-y-1">
                  <p className="font-medium">{conflict.existingNode.title}</p>
                  <p className="text-muted-foreground line-clamp-2">{conflict.existingNode.content}</p>
                  {(conflict.conflictType === "UPDATE" || conflict.conflictType === "DUPLICATE") && (
                    <Button
                      data-testid={`button-merge-${candidate.id}`}
                      variant="outline"
                      size="sm"
                      className="mt-2 h-7 text-xs w-full"
                      onClick={() => handleMerge(conflict.existingNode!.id)}
                      disabled={isPending}
                    >
                      <GitMerge className="h-3 w-3 mr-1" /> Merge into existing node
                    </Button>
                  )}
                </div>
              )}
            </div>
          )}
          {!isDetecting && !conflict && (
            <p className="text-xs text-muted-foreground">Awaiting conflict scan...</p>
          )}
        </div>

        {/* Content — editable for MEDIUM/LOW */}
        {!editing ? (
          <div className="space-y-3">
            <div>
              <p className="text-xs font-semibold text-muted-foreground mb-1">CONTENT</p>
              <p className="text-sm bg-muted/30 p-2 rounded">{candidate.content}</p>
            </div>
            {candidate.rationale && (
              <div>
                <p className="text-xs font-semibold text-muted-foreground mb-1">RATIONALE</p>
                <p className="text-sm text-muted-foreground">{candidate.rationale}</p>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-3">
            <Separator />
            <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wide">Edit before confirming</p>
            <div className="space-y-2">
              <div>
                <label className="text-xs font-medium">Type</label>
                <Select value={editedType} onValueChange={v => setEditedType(v as typeof editedType)}>
                  <SelectTrigger className="mt-1 h-8 text-sm">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {["CONSTRAINT", "DECISION", "ANTI_PATTERN", "FACT"].map(t => (
                      <SelectItem key={t} value={t}>{t}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <label className="text-xs font-medium">Title</label>
                <Input data-testid={`input-edit-title-${candidate.id}`} value={editedTitle} onChange={e => setEditedTitle(e.target.value)} className="mt-1 h-8 text-sm" />
              </div>
              <div>
                <label className="text-xs font-medium">Content</label>
                <Textarea data-testid={`input-edit-content-${candidate.id}`} value={editedContent} onChange={e => setEditedContent(e.target.value)} className="mt-1 text-sm resize-none h-24" />
              </div>
              <div>
                <label className="text-xs font-medium">Rationale</label>
                <Input data-testid={`input-edit-rationale-${candidate.id}`} value={editedRationale} onChange={e => setEditedRationale(e.target.value)} className="mt-1 h-8 text-sm" />
              </div>
            </div>
          </div>
        )}
      </CardContent>

      <CardFooter className="flex items-center justify-between pt-4 bg-muted/30">
        <Button
          data-testid={`button-dismiss-${candidate.id}`}
          variant="ghost"
          size="sm"
          onClick={onDismiss}
          disabled={isPending}
          className="text-muted-foreground hover:text-destructive"
        >
          <XCircle className="h-4 w-4 mr-1.5" /> Dismiss
        </Button>
        <div className="flex items-center gap-2">
          {requiresReview && !requiresEdit && (
            <Button
              data-testid={`button-edit-${candidate.id}`}
              variant="outline"
              size="sm"
              onClick={() => setEditing(v => !v)}
            >
              {editing ? "Cancel edit" : "Edit"}
            </Button>
          )}
          <Button
            data-testid={`button-confirm-${candidate.id}`}
            size="sm"
            onClick={handleConfirm}
            disabled={isPending || (requiresEdit && (!editedTitle.trim() || !editedContent.trim()))}
          >
            {isPending ? <Loader2 className="h-4 w-4 mr-1.5 animate-spin" /> : <CheckCircle className="h-4 w-4 mr-1.5" />}
            {tier === "HIGH" ? "Auto-capture" : "Confirm Node"}
          </Button>
        </div>
      </CardFooter>
    </Card>
  );
}

import { useGetCaptureSummary, useListEvents } from "@workspace/api-client-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Activity, Network, FileCheck, CheckCircle2, ShieldAlert, CheckSquare, AlertTriangle, Info, GitMerge, RotateCcw, Plus, Trash2 } from "lucide-react";
import { formatDistanceToNow } from "date-fns";

function typeColor(label: string) {
  if (label === "CONSTRAINT") return "bg-red-500";
  if (label === "DECISION") return "bg-primary";
  if (label === "ANTI_PATTERN") return "bg-orange-500";
  if (label === "FACT") return "bg-blue-500";
  return "bg-muted-foreground";
}

function deptColor(idx: number) {
  const colors = ["bg-teal-500", "bg-violet-500", "bg-amber-500", "bg-sky-500", "bg-rose-500", "bg-emerald-500"];
  return colors[idx % colors.length];
}

function eventIcon(type: string) {
  if (type.includes("DETECTED")) return <Activity className="h-3.5 w-3.5 text-blue-500" />;
  if (type.includes("CONFIRMED")) return <Plus className="h-3.5 w-3.5 text-green-500" />;
  if (type.includes("DISMISSED")) return <Trash2 className="h-3.5 w-3.5 text-red-500" />;
  if (type.includes("MERGED")) return <GitMerge className="h-3.5 w-3.5 text-purple-500" />;
  if (type.includes("UNDONE")) return <RotateCcw className="h-3.5 w-3.5 text-orange-500" />;
  return <Activity className="h-3.5 w-3.5 text-muted-foreground" />;
}

function eventLabel(type: string) {
  return type.replace(/CAPTURE_/, "").replace(/_/g, " ");
}

function eventBadgeVariant(type: string): "default" | "secondary" | "destructive" | "outline" {
  if (type.includes("CONFIRMED")) return "default";
  if (type.includes("DISMISSED")) return "destructive";
  if (type.includes("MERGED")) return "secondary";
  return "outline";
}

export default function Dashboard() {
  const { data: summary, isLoading, isError } = useGetCaptureSummary();
  const { data: events } = useListEvents({ limit: 20 });

  if (isLoading) {
    return (
      <div className="p-8 space-y-4 animate-pulse">
        {[...Array(4)].map((_, i) => <div key={i} className="h-24 bg-muted rounded-lg" />)}
