          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import {
  useListKnowledgeNodes,
  useUpdateKnowledgeNode,
  useListPatients,
  getListKnowledgeNodesQueryKey,
} from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import {
  Search, Filter, ShieldAlert, CheckSquare, Info, AlertTriangle,
  Pencil, X, Check, Loader2, User
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

function getTypeIcon(type: string, size = "h-4 w-4") {
  switch (type) {
    case "CONSTRAINT": return <ShieldAlert className={`${size} text-red-500`} />;
    case "DECISION": return <CheckSquare className={`${size} text-primary`} />;
    case "ANTI_PATTERN": return <AlertTriangle className={`${size} text-orange-500`} />;
    case "FACT": return <Info className={`${size} text-blue-500`} />;
    default: return <Info className={`${size}`} />;
  }
}

function typeBorderColor(type: string) {
  if (type === "CONSTRAINT") return "border-t-red-500";
  if (type === "DECISION") return "border-t-primary";
  if (type === "ANTI_PATTERN") return "border-t-orange-500";
  return "border-t-blue-500";
}

export default function KnowledgeBrowser() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [search, setSearch] = useState("");
  const [typeFilter, setTypeFilter] = useState("ALL");
  const [statusFilter, setStatusFilter] = useState("ACTIVE");
  const [patientFilter, setPatientFilter] = useState("ALL");

  const { data: patients } = useListPatients();
  const { data: nodes, isLoading } = useListKnowledgeNodes(
    statusFilter !== "ALL" || patientFilter !== "ALL"
      ? {
          ...(statusFilter !== "ALL" ? { status: statusFilter as "ACTIVE" | "PENDING_CONFIRMATION" | "DISMISSED" } : {}),
          ...(patientFilter !== "ALL" ? { patientId: Number(patientFilter) } : {}),
        }
      : undefined
  );

  const filtered = nodes?.filter(node => {
    const matchSearch = !search || node.title.toLowerCase().includes(search.toLowerCase()) || node.content.toLowerCase().includes(search.toLowerCase());
    const matchType = typeFilter === "ALL" || node.type === typeFilter;
    return matchSearch && matchType;
  });

  const counts = { total: filtered?.length ?? 0, CONSTRAINT: 0, DECISION: 0, ANTI_PATTERN: 0, FACT: 0 };
  filtered?.forEach(n => { counts[n.type as keyof typeof counts] = (counts[n.type as keyof typeof counts] as number) + 1; });

  return (
    <div className="p-8 space-y-6">
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Knowledge Graph</h1>
          <p className="text-muted-foreground mt-1">Browse, filter, and edit validated clinical knowledge nodes.</p>
        </div>
        <div className="text-right">
          <p className="text-2xl font-bold">{counts.total}</p>
          <p className="text-xs text-muted-foreground">nodes</p>
        </div>
      </div>

      {/* Type summary pills */}
      <div className="flex gap-2 flex-wrap">
        {(["CONSTRAINT", "DECISION", "ANTI_PATTERN", "FACT"] as const).map(type => (
          <button
            key={type}
            data-testid={`filter-pill-${type}`}
            onClick={() => setTypeFilter(prev => prev === type ? "ALL" : type)}
            className={`flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium border transition-colors ${typeFilter === type ? "bg-foreground text-background border-foreground" : "bg-muted/40 border-border hover:bg-muted"}`}
          >
            {getTypeIcon(type, "h-3 w-3")}
            {type.replace("_", " ")}
            <span className="text-muted-foreground">{counts[type]}</span>
          </button>
        ))}
      </div>

      {/* Filters row */}
      <div className="flex gap-3 items-center flex-wrap">
        <div className="relative flex-1 min-w-[220px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input data-testid="input-search-nodes" placeholder="Search by title or content..." className="pl-9 h-9" value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-[160px] h-9" data-testid="select-status-filter">
            <Filter className="h-3.5 w-3.5 mr-2" />
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="ALL">All Statuses</SelectItem>
            <SelectItem value="ACTIVE">Active</SelectItem>
            <SelectItem value="PENDING_CONFIRMATION">Pending</SelectItem>
            <SelectItem value="DISMISSED">Dismissed</SelectItem>
          </SelectContent>
        </Select>
        <Select value={patientFilter} onValueChange={setPatientFilter}>
          <SelectTrigger className="w-[180px] h-9" data-testid="select-patient-filter">
            <User className="h-3.5 w-3.5 mr-2" />
            <SelectValue placeholder="All patients" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="ALL">All Patients</SelectItem>
            {patients?.map(p => (
              <SelectItem key={p.id} value={p.id.toString()}>{p.name}</SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      {isLoading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {[...Array(6)].map((_, i) => <div key={i} className="h-48 bg-muted rounded-xl animate-pulse" />)}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered?.map(node => (
            <NodeCard key={node.id} node={node} onSaved={() => queryClient.invalidateQueries({ queryKey: getListKnowledgeNodesQueryKey() })} />
          ))}
          {filtered?.length === 0 && (
            <div className="col-span-full py-16 text-center border border-dashed rounded-xl bg-muted/20">
              <p className="text-muted-foreground text-sm">No nodes match your filters.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function NodeCard({ node, onSaved }: { node: ReturnType<typeof useListKnowledgeNodes>["data"] extends (infer U)[] | undefined ? U : never; onSaved: () => void }) {
  const { toast } = useToast();
  const [editing, setEditing] = useState(false);
  const [editedContent, setEditedContent] = useState(node.content);
  const [editedTitle, setEditedTitle] = useState(node.title);
  const [editedRationale, setEditedRationale] = useState(node.rationale ?? "");
  const updateNode = useUpdateKnowledgeNode();

  const handleSave = async () => {
    try {
      await updateNode.mutateAsync({
        nodeId: node.id,
        data: { title: editedTitle, content: editedContent, rationale: editedRationale },
      });
      onSaved();
      setEditing(false);
      toast({ title: "Node updated" });
    } catch {
      toast({ title: "Update failed", variant: "destructive" });
    }
  };

  const handleCancel = () => {
    setEditedContent(node.content);
    setEditedTitle(node.title);
    setEditedRationale(node.rationale ?? "");
    setEditing(false);
  };

  return (
    <Card data-testid={`node-card-${node.id}`} className={`flex flex-col border-t-2 ${typeBorderColor(node.type)} transition-shadow hover:shadow-md`}>
      <CardHeader className="pb-2">
        <div className="flex items-start justify-between gap-2">
          <div className="flex items-center gap-1.5 min-w-0">
            {getTypeIcon(node.type, "h-3.5 w-3.5 shrink-0")}
            <Badge variant="outline" className="text-[10px] h-4 shrink-0">{node.type}</Badge>
          </div>
          <div className="flex items-center gap-1 shrink-0">
            <Badge variant={node.status === "ACTIVE" ? "default" : "secondary"} className="text-[10px] h-4">{node.status.replace("_", " ")}</Badge>
          </div>
        </div>
        {!editing ? (
          <CardTitle className="text-base leading-snug mt-1">{node.title}</CardTitle>
        ) : (
          <Input data-testid={`input-node-title-${node.id}`} value={editedTitle} onChange={e => setEditedTitle(e.target.value)} className="mt-1 h-8 text-sm font-semibold" />
        )}
        <CardDescription className="text-[11px]">
          {node.level} · {node.department ?? "general"} · {(node.confidence * 100).toFixed(0)}% conf
        </CardDescription>
      </CardHeader>

      <CardContent className="flex-1 space-y-3">
        {!editing ? (
          <>
            <p className="text-sm leading-relaxed">{node.content}</p>
            {node.rationale && (
              <div className="pt-2 border-t border-border/40">
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wide mb-1">Rationale</p>
                <p className="text-xs text-muted-foreground line-clamp-2">{node.rationale}</p>
              </div>
            )}
          </>
        ) : (
          <div className="space-y-2">
            <Separator />
            <div>
              <label className="text-xs font-medium text-muted-foreground">Content</label>
              <Textarea data-testid={`input-node-content-${node.id}`} value={editedContent} onChange={e => setEditedContent(e.target.value)} className="mt-1 text-sm resize-none h-28" />
            </div>
            <div>
              <label className="text-xs font-medium text-muted-foreground">Rationale</label>
              <Input data-testid={`input-node-rationale-${node.id}`} value={editedRationale} onChange={e => setEditedRationale(e.target.value)} className="mt-1 h-8 text-sm" />
            </div>
          </div>
        )}
      </CardContent>

      <CardFooter className="pt-3 gap-2 justify-end">
        {!editing ? (
          <Button data-testid={`button-edit-node-${node.id}`} variant="ghost" size="sm" onClick={() => setEditing(true)} className="h-7 text-xs">
            <Pencil className="h-3 w-3 mr-1" /> Edit
          </Button>
        ) : (
          <>
            <Button data-testid={`button-cancel-node-${node.id}`} variant="ghost" size="sm" onClick={handleCancel} className="h-7 text-xs">
              <X className="h-3 w-3 mr-1" /> Cancel
            </Button>
            <Button data-testid={`button-save-node-${node.id}`} size="sm" onClick={handleSave} disabled={updateNode.isPending} className="h-7 text-xs">
              {updateNode.isPending ? <Loader2 className="h-3 w-3 mr-1 animate-spin" /> : <Check className="h-3 w-3 mr-1" />} Save
            </Button>
          </>
        )}
      </CardFooter>
    </Card>
  );
}

import { useState } from "react";
import { useListEvents } from "@workspace/api-client-react";
import { format, formatDistanceToNow } from "date-fns";
import { Activity, Plus, Trash2, GitMerge, RotateCcw, Search, Edit } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

function getEventIcon(type: string) {
  if (type.includes("DETECTED")) return <Activity className="h-4 w-4 text-blue-500" />;
  if (type.includes("CONFIRMED")) return <Plus className="h-4 w-4 text-green-500" />;
  if (type.includes("DISMISSED")) return <Trash2 className="h-4 w-4 text-red-500" />;
  if (type.includes("MERGED")) return <GitMerge className="h-4 w-4 text-purple-500" />;
  if (type.includes("UNDONE")) return <RotateCcw className="h-4 w-4 text-orange-500" />;
  return <Edit className="h-4 w-4 text-muted-foreground" />;
}

function getEventBg(type: string) {
  if (type.includes("DETECTED")) return "bg-blue-50 border-blue-100";
  if (type.includes("CONFIRMED")) return "bg-green-50 border-green-100";
  if (type.includes("DISMISSED")) return "bg-red-50 border-red-100";
  if (type.includes("MERGED")) return "bg-purple-50 border-purple-100";
  if (type.includes("UNDONE")) return "bg-orange-50 border-orange-100";
  return "bg-muted border-border";
}

function eventLabel(type: string) {
  return type.replace(/^CAPTURE_/, "").replace(/_/g, " ");
}

function badgeVariant(type: string): "default" | "secondary" | "destructive" | "outline" {
  if (type.includes("CONFIRMED")) return "default";
  if (type.includes("DISMISSED") || type.includes("UNDONE")) return "destructive";
  if (type.includes("MERGED")) return "secondary";
  return "outline";
}

const EVENT_TYPES = ["ALL", "CAPTURE_DETECTED", "CAPTURE_CONFIRMED", "CAPTURE_DISMISSED", "CAPTURE_MERGED", "CAPTURE_UNDONE"];

export default function EventLog() {
  const [search, setSearch] = useState("");
  const [typeFilter, setTypeFilter] = useState("ALL");
  const [limit, setLimit] = useState(100);

  const { data: events, isLoading } = useListEvents({ limit });

  const filtered = events?.filter(e => {
    const matchType = typeFilter === "ALL" || e.eventType === typeFilter;
    const matchSearch = !search || e.eventType.includes(search.toUpperCase()) || String(e.nodeId ?? "").includes(search) || String(e.patientId ?? "").includes(search);
    return matchType && matchSearch;
  });

  return (
    <div className="p-8 space-y-6 max-w-5xl mx-auto">
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Event Log</h1>
          <p className="text-muted-foreground mt-1">Full audit trail of all pipeline decisions and actions.</p>
        </div>
        <div className="text-right">
          <p className="text-2xl font-bold">{filtered?.length ?? 0}</p>
          <p className="text-xs text-muted-foreground">events</p>
        </div>
      </div>

      {/* Filters */}
      <div className="flex gap-3 items-center">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input data-testid="input-search-events" placeholder="Search events..." className="pl-9 h-9" value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <Select value={typeFilter} onValueChange={setTypeFilter}>
          <SelectTrigger className="w-[220px] h-9" data-testid="select-event-type-filter">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            {EVENT_TYPES.map(t => (
              <SelectItem key={t} value={t}>{t === "ALL" ? "All Event Types" : t.replace(/^CAPTURE_/, "").replace(/_/g, " ")}</SelectItem>
            ))}
          </SelectContent>
        </Select>
        <Select value={String(limit)} onValueChange={v => setLimit(Number(v))}>
          <SelectTrigger className="w-[100px] h-9">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            {[50, 100, 250, 500].map(n => <SelectItem key={n} value={String(n)}>Last {n}</SelectItem>)}
          </SelectContent>
        </Select>
      </div>

      <Card>
        <CardHeader className="pb-0 pt-4 px-4">
          <CardTitle className="text-sm text-muted-foreground font-normal">{filtered?.length ?? 0} events</CardTitle>
        </CardHeader>
        <CardContent className="p-0 mt-2">
          {isLoading ? (
            <div className="p-8 text-center text-muted-foreground text-sm">Loading events...</div>
          ) : !filtered?.length ? (
            <div className="p-12 text-center text-muted-foreground text-sm border-t border-border">No events match your filter.</div>
          ) : (
            <div className="divide-y divide-border">
              {filtered.map((event, idx) => {
                const meta = event.metadata as Record<string, unknown> | null;
                return (
                  <div key={event.id} data-testid={`event-row-${event.id}`} className="flex gap-4 px-4 py-3 hover:bg-muted/30 transition-colors group">
                    {/* Timeline line */}
                    <div className="flex flex-col items-center gap-1 shrink-0">
                      <div className={`h-8 w-8 rounded-full border flex items-center justify-center ${getEventBg(event.eventType)}`}>
                        {getEventIcon(event.eventType)}
                      </div>
                      {idx < (filtered.length - 1) && <div className="flex-1 w-px bg-border min-h-[8px]" />}
                    </div>

                    {/* Content */}
                    <div className="flex-1 min-w-0 pt-1 pb-2 space-y-1.5">
                      <div className="flex items-center gap-2 flex-wrap">
                        <Badge variant={badgeVariant(event.eventType)} className="text-xs h-5">
                          {eventLabel(event.eventType)}
                        </Badge>
                        {event.nodeId && (
                          <span className="text-xs text-muted-foreground">Node #{event.nodeId}</span>
                        )}
                        {event.candidateId && (
                          <span className="text-xs text-muted-foreground">Candidate #{event.candidateId}</span>
                        )}
                      </div>
                      <div className="flex gap-3 flex-wrap">
                        {event.patientId && <span className="text-xs text-muted-foreground">Patient #{event.patientId}</span>}
                        {event.doctorId && <span className="text-xs text-muted-foreground">· Doctor #{event.doctorId}</span>}
                        {meta && Object.keys(meta).length > 0 && (
                          <span className="text-xs text-muted-foreground">
                            {Object.entries(meta).map(([k, v]) => `${k}: ${v}`).join(" · ")}
                          </span>
                        )}
                      </div>
                    </div>

                    {/* Timestamp */}
                    <div className="shrink-0 text-right pt-1 space-y-0.5">
                      <p className="text-xs text-muted-foreground">{formatDistanceToNow(new Date(event.createdAt), { addSuffix: true })}</p>
                      <p className="text-[10px] text-muted-foreground/60">{format(new Date(event.createdAt), "HH:mm:ss")}</p>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

