import { Layout } from "@/components/layout";
import Dashboard from "@/pages/dashboard";
import Pipeline from "@/pages/pipeline";
import KnowledgeBrowser from "@/pages/knowledge";
import EventLog from "@/pages/events";
import Manage from "@/pages/manage";
import NotFound from "@/pages/not-found";
import { Switch, Route, Router as WouterRouter } from "wouter";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";

const queryClient = new QueryClient();

function Router() {
  return (
    <Layout>
      <Switch>
        <Route path="/" component={Dashboard} />
        <Route path="/pipeline" component={Pipeline} />
        <Route path="/knowledge" component={KnowledgeBrowser} />
        <Route path="/events" component={EventLog} />
        <Route path="/manage" component={Manage} />
        <Route component={NotFound} />
      </Switch>
    </Layout>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
          <Router />
        </WouterRouter>
        <Toaster />
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

import { ReactNode } from "react";
import { Link, useLocation } from "wouter";
import { Activity, Network, History, FileAudio, Users } from "lucide-react";
import { Sidebar, SidebarContent, SidebarHeader, SidebarMenu, SidebarMenuItem, SidebarMenuButton, SidebarProvider } from "@/components/ui/sidebar";

const NAV = [
  { href: "/", label: "Dashboard", icon: Activity },
  { href: "/pipeline", label: "Pipeline", icon: FileAudio },
  { href: "/knowledge", label: "Knowledge Graph", icon: Network },
  { href: "/events", label: "Event Log", icon: History },
  { href: "/manage", label: "Manage", icon: Users },
];

export function Layout({ children }: { children: ReactNode }) {
  const [location] = useLocation();

  return (
    <SidebarProvider>
      <div className="min-h-screen flex w-full bg-background">
        <Sidebar className="border-r border-border bg-card">
          <SidebarHeader className="p-4 flex items-center justify-center border-b border-border">
            <div className="flex items-center gap-2 text-primary font-bold text-lg tracking-tight">
              <Activity className="h-5 w-5" />
              <span>MedCapture</span>
            </div>
          </SidebarHeader>
          <SidebarContent>
            <SidebarMenu className="p-2 gap-0.5">
              {NAV.map(({ href, label, icon: Icon }) => (
                <SidebarMenuItem key={href}>
                  <SidebarMenuButton asChild isActive={location === href}>
                    <Link href={href} data-testid={`nav-${label.toLowerCase().replace(/ /g, "-")}`}>
                      <Icon className="h-4 w-4 mr-2" />
                      {label}
                    </Link>
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarContent>
        </Sidebar>
        <main className="flex-1 flex flex-col min-h-0 overflow-hidden">
          <div className="flex-1 overflow-auto">
            {children}
          </div>
        </main>
      </div>
    </SidebarProvider>
  );
}

