                </form>
              </Form>
            </DialogContent>
          </Dialog>
        </div>

        {loadingDoctors ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {[...Array(3)].map((_, i) => <div key={i} className="h-28 rounded-xl bg-muted animate-pulse" />)}
          </div>
        ) : doctors?.length === 0 ? (
          <EmptyState icon={<Stethoscope className="h-8 w-8" />} label="No doctors yet" action={<Button size="sm" onClick={() => setDoctorDialogOpen(true)}><Plus className="h-4 w-4 mr-1" /> Add first doctor</Button>} />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
